// // This module decodes a 2-bit input to produce a 1-bit output 'q' which is the least significant bit of the input, and a 1-bit output 'zero' which is high if either bit of the input is high.
module two_bit_encoder (
    input [1:0] data,
    output reg q,
    output reg zero
);

    always @(*) begin
        q = data[1];
        zero = ~(|data);
    end

endmodule
